const raw = $input.first().json;
let d = raw;
if (typeof raw.data === 'string') { try { d = JSON.parse(raw.data); } catch(e){} }
else if (raw.data && typeof raw.data === 'object') d = raw.data;

let errMsg = '';
if (d && d.message && !d.organic) errMsg = 'Serper: ' + d.message;

const siteHost = (($node.Webhook.json.body.site_host) || '').replace(/^www\./,'').toLowerCase();
const organic = d.organic || [];
let rank = null, foundUrl = null;
for (let i = 0; i < organic.length; i++) {
  const link = organic[i].link || '';
  let h = '';
  try { h = new URL(link).hostname.replace(/^www\./,'').toLowerCase(); } catch(e){}
  if (h && siteHost && h === siteHost) { rank = organic[i].position || (i + 1); foundUrl = link; break; }
}

return [{json: {
  keyword: $node.Webhook.json.body.keyword || '',
  rank: rank,
  found_url: foundUrl,
  total_results: organic.length,
  error: errMsg
}}];
